```py
function prepareCanvas() {
const canvas = document.getElementById('draw-canvas');
canvas.width = canvasSize;
canvas.height = canvasSize;
ctx = canvas.getContext('2d');
ctx.strokeStyle = 'white';
ctx.fillStyle = 'white';
ctx.lineJoin = 'round';
ctx.lineCap = 'round';
ctx.lineWidth = 15;
}
```

```py
canvas.addEventListener('mousedown', (e) => {
drawing = true;
lastPosition = { x: e.offsetX, y: e.offsetY };
});
canvas.addEventListener('mouseout', () => {
drawing = false;
});
```

```py
canvas.addEventListener('mousemove', (e) => {
if (!drawing) {
return;
}
ctx.beginPath();
ctx.moveTo(lastPosition.x, lastPosition.y);
ctx.lineTo(e.offsetX, e.offsetY);
ctx.stroke();
lastPosition = { x: e.offsetX, y: e.offsetY };
});
```

```py
canvas.addEventListener('mouseup', () => {
drawing = false;
if (!isModelTrained) {
return;
}
const toPredict = tf.browser.fromPixels(canvas)
.resizeBilinear([IMAGE_SIZE, IMAGE_SIZE])
.mean(2)
.expandDims()
.expandDims(3)
.toFloat()
.div(255.0);
const prediction = model.predict(toPredict).dataSync();
const p = document
.getElementById('predict-output');
p.innerHTML = `Predicted value is: ${tf.argMax(prediction).dataSync()}`;
});
